SELECT c.*, cd_ct.code_label AS coupon_type_cd_nm, cd_cs.code_label AS coupon_status_cd_nm, cd_mg.code_label AS mem_grade_cd_nm FROM pm_coupon c LEFT JOIN sy_code cd_ct ON cd_ct.code_grp = 'COUPON_TYPE' AND cd_ct.code_value = c.coupon_type_cd LEFT JOIN sy_code cd_cs ON cd_cs.code_grp = 'COUPON_STATUS' AND cd_cs.code_value = c.coupon_status_cd LEFT JOIN sy_code cd_mg ON cd_mg.code_grp = 'MEMBER_GRADE' AND cd_mg.code_value = c.mem_grade_cd
ORDER BY c.coupon_id ASC ORDER BY c.coupon_id DESC ORDER BY c.coupon_nm ASC ORDER BY c.coupon_nm DESC ORDER BY c.reg_date ASC ORDER BY c.reg_date DESC ORDER BY c.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

SELECT c.*, cd_ct.code_label AS coupon_type_cd_nm, cd_cs.code_label AS coupon_status_cd_nm, cd_mg.code_label AS mem_grade_cd_nm FROM pm_coupon c LEFT JOIN sy_code cd_ct ON cd_ct.code_grp = 'COUPON_TYPE' AND cd_ct.code_value = c.coupon_type_cd LEFT JOIN sy_code cd_cs ON cd_cs.code_grp = 'COUPON_STATUS' AND cd_cs.code_value = c.coupon_status_cd LEFT JOIN sy_code cd_mg ON cd_mg.code_grp = 'MEMBER_GRADE' AND cd_mg.code_value = c.mem_grade_cd
ORDER BY c.coupon_id ASC ORDER BY c.coupon_id DESC ORDER BY c.coupon_nm ASC ORDER BY c.coupon_nm DESC ORDER BY c.reg_date ASC ORDER BY c.reg_date DESC ORDER BY c.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

