coupon_status_cd = #{couponStatusCd}, coupon_status_cd_before = #{couponStatusCdBefore}, coupon_nm = #{couponNm}, use_yn = #{useYn}, valid_from = #{validFrom}, valid_to = #{validTo}, issue_cnt = #{issueCnt}, memo = #{memo}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE coupon_id = #{couponId}
